using System.ComponentModel.DataAnnotations;

namespace DocSummary.Models;

public class SummarizeRequest
{
    [Required]
    [MinLength(1)]
    public required string DocumentText { get; set; }

    /// <summary>
    /// Maximum number of sentences in the summary. Defaults to 3.
    /// </summary>
    [Range(1, 20)]
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public required string Summary { get; set; }
    public int OriginalLength { get; set; }
    public int SummaryLength { get; set; }
}

namespace DocSummary.Services;

public interface IDocumentSummarizer
{
    string Summarize(string text, int maxSentences);
}

/// <summary>
/// Extractive summarizer that scores sentences by word frequency
/// and returns the top-ranked ones in their original order.
/// </summary>
public class DocumentSummarizer : IDocumentSummarizer
{
    private static readonly char[] SentenceDelimiters = ['.', '!', '?'];

    public string Summarize(string text, int maxSentences)
    {
        ArgumentException.ThrowIfNullOrWhiteSpace(text);
        ArgumentOutOfRangeException.ThrowIfLessThan(maxSentences, 1);

        var sentences = SplitIntoSentences(text);

        if (sentences.Count <= maxSentences)
            return string.Join(" ", sentences);

        var wordFrequencies = BuildWordFrequencies(sentences);
        var scoredSentences = ScoreSentences(sentences, wordFrequencies);

        // Pick top-scoring sentences but preserve original order.
        var topIndices = scoredSentences
            .OrderByDescending(s => s.Score)
            .Take(maxSentences)
            .Select(s => s.Index)
            .Order()
            .ToList();

        return string.Join(" ", topIndices.Select(i => sentences[i]));
    }

    private static List<string> SplitIntoSentences(string text)
    {
        var sentences = new List<string>();
        int start = 0;

        for (int i = 0; i < text.Length; i++)
        {
            if (SentenceDelimiters.Contains(text[i]))
            {
                var sentence = text[start..(i + 1)].Trim();
                if (sentence.Length > 0)
                    sentences.Add(sentence);
                start = i + 1;
            }
        }

        // Capture trailing text without a delimiter.
        if (start < text.Length)
        {
            var remaining = text[start..].Trim();
            if (remaining.Length > 0)
                sentences.Add(remaining);
        }

        return sentences;
    }

    private static Dictionary<string, int> BuildWordFrequencies(List<string> sentences)
    {
        var freq = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);

        foreach (var sentence in sentences)
        {
            foreach (var word in ExtractWords(sentence))
            {
                if (freq.TryGetValue(word, out int count))
                    freq[word] = count + 1;
                else
                    freq[word] = 1;
            }
        }

        return freq;
    }

    private static List<(int Index, double Score)> ScoreSentences(
        List<string> sentences, Dictionary<string, int> wordFrequencies)
    {
        var scored = new List<(int Index, double Score)>(sentences.Count);

        for (int i = 0; i < sentences.Count; i++)
        {
            var words = ExtractWords(sentences[i]);
            double score = words.Count == 0
                ? 0
                : words.Sum(w => wordFrequencies.GetValueOrDefault(w, 0)) / (double)words.Count;
            scored.Add((i, score));
        }

        return scored;
    }

    private static List<string> ExtractWords(string sentence) =>
        sentence
            .Split(' ', StringSplitOptions.RemoveEmptyEntries)
            .Select(w => w.Trim('.', ',', '!', '?', ';', ':', '"', '\'', '(', ')'))
            .Where(w => w.Length > 0)
            .ToList();
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummarizeController(IDocumentSummarizer summarizer) : ControllerBase
{
    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        var summary = summarizer.Summarize(request.DocumentText, request.MaxSentences);

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalLength = request.DocumentText.Length,
            SummaryLength = summary.Length
        });
    }
}

